function createRenderer() {
  var points = [];
  var bars = [];
  var initialized = false;
  function clamp(x){ return Math.max(0, Math.min(1, x)); }
  function ease(x){ x=clamp(x); return 1 - Math.pow(1-x, 3); }
  function easeIO(x){ x=clamp(x); return x < .5 ? 4*x*x*x : 1 - Math.pow(-2*x+2,3)/2; }
  function rr(ctx,x,y,w,h,r){ ctx.beginPath(); ctx.moveTo(x+r,y); ctx.lineTo(x+w-r,y); ctx.quadraticCurveTo(x+w,y,x+w,y+r); ctx.lineTo(x+w,y+h-r); ctx.quadraticCurveTo(x+w,y+h,x+w-r,y+h); ctx.lineTo(x+r,y+h); ctx.quadraticCurveTo(x,y+h,x,y+h-r); ctx.lineTo(x,y+r); ctx.quadraticCurveTo(x,y,x+r,y); ctx.closePath(); }
  function init(){ if(initialized) return; initialized=true; for(var i=0;i<220;i++){ points.push({x:Math.random()*1920,y:Math.random()*1080,a:Math.random()*6.28,s:.3+Math.random()*1.6,r:1+Math.random()*3}); } for(var b=0;b<36;b++){ bars.push({v:.2+Math.random()*.7, phase:Math.random()*6.28}); } }
  function render(t, context){ init(); var ctx=context.mainContext, W=context.width, H=context.height; var scene=Math.floor(t/3); var local=t-scene*3; var p=local/3; background(ctx,W,H,t,scene); if(scene===0) sceneIntro(ctx,W,H,t,p); if(scene===1) sceneData(ctx,W,H,t,p); if(scene===2) sceneDepth(ctx,W,H,t,p); if(scene>=3) sceneExport(ctx,W,H,t,p); hud(ctx,W,H,t,scene,p); }
  function background(ctx,W,H,t,scene){ var colors=[['#05070f','#0b1d34','#162016'],['#061018','#102542','#1b4332'],['#090814','#1a1638','#3a0f2f'],['#040b10','#0a2725','#1f2a12']][scene] || ['#05070f','#0b1d34','#162016']; var g=ctx.createLinearGradient(0,0,W,H); g.addColorStop(0,colors[0]); g.addColorStop(.56,colors[1]); g.addColorStop(1,colors[2]); ctx.fillStyle=g; ctx.fillRect(0,0,W,H); ctx.save(); ctx.globalAlpha=.12; ctx.strokeStyle='#ffffff'; for(var x=-160;x<W+160;x+=80){ ctx.beginPath(); ctx.moveTo(x+(t*18)%80,0); ctx.lineTo(x-260+(t*18)%80,H); ctx.stroke(); } ctx.restore(); }
  function sceneIntro(ctx,W,H,t,p){ var e=ease(p); for(var i=0;i<points.length;i++){ var pt=points[i]; var x=(pt.x+Math.cos(t*pt.s+pt.a)*70+W)%W; var y=(pt.y+Math.sin(t*pt.s+pt.a)*45+H)%H; ctx.fillStyle='rgba(0,212,255,.55)'; ctx.beginPath(); ctx.arc(x,y,pt.r,0,Math.PI*2); ctx.fill(); }
    ctx.textAlign='center'; ctx.fillStyle='#fff'; ctx.font='900 96px Arial'; ctx.shadowColor='#00d4ff'; ctx.shadowBlur=30; ctx.fillText('RENDER LAB',W/2,H/2-80+(1-e)*40); ctx.shadowBlur=0; ctx.fillStyle='#d7e6f4'; ctx.font='30px Arial'; ctx.fillText('Data, depth, particles, and export timing in one JSON project',W/2,H/2+2); badges(ctx,W/2,H/2+100,e,['JSON','Canvas','Runtime','WebCodecs']); }
  function sceneData(ctx,W,H,t,p){ var e=ease(p); ctx.textAlign='left'; ctx.fillStyle='#fff'; ctx.font='900 62px Arial'; ctx.fillText('Live data story',120,150); ctx.fillStyle='#a9bdd2'; ctx.font='24px Arial'; ctx.fillText('Charts are regular Canvas instructions, so data can be swapped by code.',124,198); var base=830; for(var i=0;i<bars.length;i++){ var x=140+i*45; var h=(180+Math.sin(t*1.5+bars[i].phase)*80+bars[i].v*360)*e; var grad=ctx.createLinearGradient(x,base-h,x,base); grad.addColorStop(0,i%3===0?'#f2aa4c':i%3===1?'#00d4ff':'#7bd88f'); grad.addColorStop(1,'rgba(255,255,255,.12)'); ctx.fillStyle=grad; rr(ctx,x,base-h,28,h,8); ctx.fill(); }
    ctx.strokeStyle='#fff'; ctx.globalAlpha=.68; ctx.lineWidth=4; ctx.beginPath(); for(var k=0;k<180;k++){ var xx=140+k*(W-280)/179; var yy=420+Math.sin(k*.12+t*2)*52+Math.cos(k*.031+t)*78; if(k===0)ctx.moveTo(xx,yy); else ctx.lineTo(xx,yy); } ctx.stroke(); ctx.globalAlpha=1; }
  function sceneDepth(ctx,W,H,t,p){ var e=ease(p); var cx=W/2, cy=H/2+20; ctx.textAlign='center'; ctx.fillStyle='#fff'; ctx.font='900 62px Arial'; ctx.fillText('Pseudo-3D without assets',cx,140); var verts=[]; var size=230; for(var x=-1;x<=1;x+=2) for(var y=-1;y<=1;y+=2) for(var z=-1;z<=1;z+=2) verts.push(project(x*size,y*size,z*size,t*.55,t*.75,cx,cy)); var edges=[[0,1],[0,2],[0,4],[3,1],[3,2],[3,7],[5,1],[5,4],[5,7],[6,2],[6,4],[6,7]]; ctx.strokeStyle='#f2aa4c'; ctx.lineWidth=6; ctx.shadowBlur=20; ctx.shadowColor='#f2aa4c'; for(var i=0;i<edges.length;i++){ var a=verts[edges[i][0]], b=verts[edges[i][1]]; ctx.beginPath(); ctx.moveTo(a.x,a.y); ctx.lineTo(b.x,b.y); ctx.stroke(); } ctx.shadowBlur=0; for(var r=0;r<18;r++){ ctx.strokeStyle='rgba(0,212,255,'+(.08+r*.018)+')'; ctx.beginPath(); ctx.ellipse(cx,cy,150+r*34,48+r*10,t*.1+r*.12,0,Math.PI*2); ctx.stroke(); } badges(ctx,cx,850,e,['camera','matrix','route','draw commands']); }
  function sceneExport(ctx,W,H,t,p){ var e=easeIO(p); ctx.textAlign='center'; ctx.fillStyle='#fff'; ctx.font='900 82px Arial'; ctx.fillText('EXPORT READY',W/2,260); ctx.fillStyle='#b8ffe8'; ctx.font='30px Arial'; ctx.fillText('The same timeline can preview, inspect, and render.',W/2,324); var steps=['validate','preview','inspect','render','mp4']; for(var i=0;i<steps.length;i++){ var x=420+i*270, y=560; ctx.globalAlpha=e; ctx.fillStyle='rgba(255,255,255,.10)'; rr(ctx,x-86,y-54,172,108,18); ctx.fill(); ctx.strokeStyle=i===4?'#f2aa4c':'#00d4ff'; ctx.stroke(); ctx.fillStyle='#eef6ff'; ctx.font='800 26px Arial'; ctx.fillText(steps[i],x,y+8); if(i<steps.length-1){ ctx.strokeStyle='rgba(255,255,255,.35)'; ctx.beginPath(); ctx.moveTo(x+94,y); ctx.lineTo(x+176,y); ctx.stroke(); } } ctx.globalAlpha=1; }
  function hud(ctx,W,H,t,scene,p){ ctx.fillStyle='rgba(0,0,0,.38)'; rr(ctx,48,46,360,104,16); ctx.fill(); ctx.fillStyle='#dff6ff'; ctx.font='18px monospace'; ctx.fillText('render-lab flagship',72,84); ctx.fillStyle='#7bd88f'; ctx.fillText('1920x1080 / 30fps / '+Math.floor(t*30)+' frames',72,116); ctx.fillStyle='rgba(255,255,255,.14)'; rr(ctx,120,H-74,W-240,12,6); ctx.fill(); var g=ctx.createLinearGradient(120,0,W-120,0); g.addColorStop(0,'#00d4ff'); g.addColorStop(1,'#f2aa4c'); ctx.fillStyle=g; rr(ctx,120,H-74,(W-240)*clamp(t/12),12,6); ctx.fill(); }
  function badges(ctx,cx,y,e,items){ ctx.save(); ctx.textAlign='center'; for(var i=0;i<items.length;i++){ var x=cx-(items.length-1)*105+i*210; ctx.globalAlpha=e; ctx.fillStyle='rgba(4,12,24,.72)'; rr(ctx,x-78,y-34,156,68,14); ctx.fill(); ctx.strokeStyle=i%2?'#f2aa4c':'#00d4ff'; ctx.stroke(); ctx.fillStyle='#eef6ff'; ctx.font='800 19px Arial'; ctx.fillText(items[i],x,y+6); } ctx.restore(); }
  function project(x,y,z,rx,ry,cx,cy){ var x1=x*Math.cos(ry)-z*Math.sin(ry); var z1=x*Math.sin(ry)+z*Math.cos(ry); var y1=y*Math.cos(rx)-z1*Math.sin(rx); var z2=y*Math.sin(rx)+z1*Math.cos(rx); var s=900/(900+z2); return {x:cx+x1*s,y:cy+y1*s,z:z2,scale:s}; }
  return { render: render };
}
